import{_ as l,H as s,f as i,i as e}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"云服务与互联网基础常识系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/00-写作计划.md","filePath":"cloudBasicsLearning/00-写作计划.md","lastUpdated":1779559313000}'),t={name:"cloudBasicsLearning/00-写作计划.md"};function n(p,a,d,r,o,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="云服务与互联网基础常识系列写作计划" tabindex="-1">云服务与互联网基础常识系列写作计划 <a class="header-anchor" href="#云服务与互联网基础常识系列写作计划" aria-label="Permalink to &quot;云服务与互联网基础常识系列写作计划&quot;">​</a></h1><blockquote><p>这个系列面向准备做网站、App、SaaS、独立开发、云部署的人。 它不追求某个厂商的操作手册,而是把 DNS、CDN、SSL、SLA、Serverless、对象存储、计费、安全、监控这些经常听到但容易混淆的概念讲清楚。 目标是:看到一个云服务免费套餐、架构图、账单、故障公告、安全配置时,能知道它在说什么、影响什么、风险在哪里。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>五层结构,从访问一个网站开始,一路讲到上线、稳定、安全和成本:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>互联网入口(DNS / 域名 / HTTPS / CDN)</span></span>
<span class="line"><span>   -&gt; 云资源抽象(服务器 / 存储 / 数据库 / Serverless)</span></span>
<span class="line"><span>   -&gt; 稳定性与运维(SLA / 监控 / 日志 / 备份 / 灾备)</span></span>
<span class="line"><span>   -&gt; 安全与权限(WAF / DDoS / IAM / 密钥 / 合规)</span></span>
<span class="line"><span>   -&gt; 计费与选型(免费额度 / 带宽 / 请求数 / 成本估算 / 厂商比较)</span></span></code></pre></div><p>本系列不写成厂商文档翻译,而是用真实问题驱动:</p><ul><li>Cloudflare 免费套餐到底免费在哪里?</li><li>99.9% SLA 是不是很高?</li><li>CDN 为什么能加速,什么时候反而会出问题?</li><li>对象存储为什么便宜,和网盘、服务器硬盘有什么区别?</li><li>Serverless 是不是完全不用管服务器?</li><li>免费额度用完会发生什么?</li><li>怎么看懂云服务账单?</li></ul><p>每篇都要回答四个问题:</p><ol><li>这个概念解决什么问题</li><li>它在真实系统里放在哪一层</li><li>免费套餐或小团队使用时最容易踩什么坑</li><li>什么时候需要升级到更专业的方案</li></ol><hr><h2 id="篇目规划" tabindex="-1">篇目规划 <a class="header-anchor" href="#篇目规划" aria-label="Permalink to &quot;篇目规划&quot;">​</a></h2><h3 id="第一层-互联网入口与访问链路-01-08" tabindex="-1">第一层:互联网入口与访问链路(01-08) <a class="header-anchor" href="#第一层-互联网入口与访问链路-01-08" aria-label="Permalink to &quot;第一层:互联网入口与访问链路(01-08)&quot;">​</a></h3><ul><li>[x] 01 云服务与互联网基础常识总览</li><li>[x] 02 域名是什么:注册商、注册局、DNS 托管的区别</li><li>[x] 03 DNS 解析:记录类型、TTL、权威 DNS、递归 DNS</li><li>[x] 04 IP、端口与 HTTP:用户访问网站时发生了什么</li><li>[x] 05 HTTPS 与证书:SSL/TLS、CA、自动续期、证书错误</li><li>[x] 06 CDN 是什么:缓存、边缘节点、回源、命中率</li><li>[x] 07 反向代理与网关:Nginx、Cloudflare、API Gateway 的位置</li><li>[x] 08 WAF 与 DDoS 防护:它们能挡什么,挡不了什么</li></ul><h3 id="第二层-云资源与部署模型-09-17" tabindex="-1">第二层:云资源与部署模型(09-17) <a class="header-anchor" href="#第二层-云资源与部署模型-09-17" aria-label="Permalink to &quot;第二层:云资源与部署模型(09-17)&quot;">​</a></h3><ul><li>[x] 09 云服务器是什么:CPU、内存、磁盘、带宽、地域</li><li>[x] 10 共享主机、VPS、云服务器、裸金属的区别</li><li>[x] 11 容器与镜像:为什么部署不只是上传代码</li><li>[x] 12 Kubernetes 是什么:适合谁,不适合谁</li><li>[x] 13 Serverless 是什么:函数、冷启动、触发器、限制</li><li>[x] 14 静态托管与前端部署:Pages、Vercel、Netlify、OSS 静态站</li><li>[x] 15 对象存储:Bucket、Object、S3、R2、OSS、生命周期</li><li>[x] 16 数据库服务:托管数据库、读写额度、连接数、备份</li><li>[x] 17 队列、缓存与消息:Redis、MQ、异步任务的常识</li></ul><h3 id="第三层-稳定性、可观测性与恢复-18-25" tabindex="-1">第三层:稳定性、可观测性与恢复(18-25) <a class="header-anchor" href="#第三层-稳定性、可观测性与恢复-18-25" aria-label="Permalink to &quot;第三层:稳定性、可观测性与恢复(18-25)&quot;">​</a></h3><ul><li>[x] 18 SLA / SLO / SLI:服务承诺、内部目标、真实指标</li><li>[x] 19 Uptime 与 Downtime:99%、99.9%、99.99% 到底差多少</li><li>[x] 20 延迟、吞吐量与并发:性能指标怎么读</li><li>[x] 21 监控是什么:指标、日志、链路追踪的分工</li><li>[x] 22 告警是什么:阈值、误报、漏报、升级路径</li><li>[x] 23 日志保留与审计:为什么免费套餐常限制日志时间</li><li>[x] 24 备份、快照与恢复:备份不是有文件就行</li><li>[x] 25 容灾与多地域:高可用、故障切换、成本边界</li></ul><h3 id="第四层-安全、身份与权限-26-33" tabindex="-1">第四层:安全、身份与权限(26-33) <a class="header-anchor" href="#第四层-安全、身份与权限-26-33" aria-label="Permalink to &quot;第四层:安全、身份与权限(26-33)&quot;">​</a></h3><ul><li>[x] 26 账号安全:Root 账号、MFA、子账号、最小权限</li><li>[x] 27 IAM 是什么:用户、角色、策略、临时凭证</li><li>[x] 28 API Key、Token 与 Secret:怎么存、怎么轮换、怎么泄露</li><li>[x] 29 OAuth、OIDC 与 SSO:登录不是自己存密码这么简单</li><li>[x] 30 CORS、Cookie 与跨域:前后端联调最常见的安全边界</li><li>[x] 31 防刷与 Bot 管理:验证码、限流、风控、误杀</li><li>[x] 32 合规与数据位置:隐私政策、数据跨境、日志敏感信息</li><li>[x] 33 安全责任共担模型:云厂商负责什么,你负责什么</li></ul><h3 id="第五层-计费、免费套餐与选型-34-42" tabindex="-1">第五层:计费、免费套餐与选型(34-42) <a class="header-anchor" href="#第五层-计费、免费套餐与选型-34-42" aria-label="Permalink to &quot;第五层:计费、免费套餐与选型(34-42)&quot;">​</a></h3><ul><li>[x] 34 云服务计费模型:按量、包年包月、预留、阶梯价</li><li>[x] 35 免费额度怎么看:请求数、存储量、出站流量、构建分钟</li><li>[x] 36 带宽与流量费:为什么出口流量最容易超预算</li><li>[x] 37 请求数与操作数:API 调用、Class A/B、读写次数</li><li>[x] 38 构建次数与运行时间:CI/CD、Pages、Serverless 的隐形限制</li><li>[x] 39 账单与预算告警:小项目也要设置成本护栏</li><li>[x] 40 Cloudflare 免费套餐拆解:适合什么,不适合什么</li><li>[x] 41 Vercel / Netlify / Firebase / Supabase 免费套餐怎么看</li><li>[x] 42 小团队云服务选型:从 0 到 1 的保守架构</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>TCP / HTTP / DNS 协议细节</td><td>networkLearning</td><td>只讲使用者需要理解的常识和排障入口</td></tr><tr><td>后端部署、容器、K8s</td><td>backendLearning / devopsLearning</td><td>只讲概念位置、选择边界和套餐限制</td></tr><tr><td>SRE、监控、告警、事故复盘</td><td>devopsLearning</td><td>只讲入门常识和小团队如何理解</td></tr><tr><td>Web 安全、渗透测试</td><td>securityLearning</td><td>只讲云服务用户必须知道的配置和责任</td></tr><tr><td>系统设计高可用与扩展</td><td>systemDesign</td><td>只讲云产品层面的可用性、成本和取舍</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇使用固定结构:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 一句话解释</span></span>
<span class="line"><span>   - 这个词到底是什么意思</span></span>
<span class="line"><span>   - 它最容易和什么概念混淆</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 放在系统哪里</span></span>
<span class="line"><span>   - 用户请求链路中的位置</span></span>
<span class="line"><span>   - 和相邻组件的关系</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 常见套餐限制</span></span>
<span class="line"><span>   - 免费额度通常限制什么</span></span>
<span class="line"><span>   - 超额后可能发生什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 小团队建议</span></span>
<span class="line"><span>   - 什么时候够用</span></span>
<span class="line"><span>   - 什么时候该升级</span></span>
<span class="line"><span>   - 最低限度的安全和成本护栏</span></span></code></pre></div><p>写作原则:</p><ul><li>多用真实场景,少堆术语定义。</li><li>每篇尽量给出一个小例子,例如一次域名解析、一次 CDN 回源、一次账单超额。</li><li>不绑定单一厂商,但可以用 Cloudflare、Vercel、AWS、阿里云、腾讯云等做对照。</li><li>不写过时价格表,价格和额度只写查看方法；需要具体数字时标注查询日期。</li></ul><hr><h2 id="推荐学习顺序" tabindex="-1">推荐学习顺序 <a class="header-anchor" href="#推荐学习顺序" aria-label="Permalink to &quot;推荐学习顺序&quot;">​</a></h2><p>如果只想看懂免费套餐和部署网站:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 02 -&gt; 03 -&gt; 05 -&gt; 06 -&gt; 14 -&gt; 15 -&gt; 18 -&gt; 34 -&gt; 35 -&gt; 40 -&gt; 42</span></span></code></pre></div><p>如果准备独立开发一个小型 SaaS:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-08 -&gt; 13-17 -&gt; 18-25 -&gt; 26-29 -&gt; 34-42</span></span></code></pre></div><p>如果目标是补齐云服务常识:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>按 01-42 顺序读,每层读完后用一个真实产品套餐页做拆解练习。</span></span></code></pre></div>`,39)])])}const x=l(t,[["render",n]]);export{u as __pageData,x as default};
